    44→// Config contains all of Flipts configuration needs.
    45→//
    46→// The root of this structure contains a collection of sub-configuration categories.
    47→//
    48→// Each sub-configuration (e.g. LogConfig) optionally implements either or both of
    49→// the defaulter or validator interfaces.
    50→// Given the sub-config implements a `setDefaults(*viper.Viper) []string` method
    51→// then this will be called with the viper context before unmarshalling.
    52→// This allows the sub-configuration to set any appropriate defaults.
    53→// Given the sub-config implements a `validate() error` method
    54→// then this will be called after unmarshalling, such that the function can emit
    55→// any errors derived from the resulting state of the configuration.
    56→type Config struct {
    57→	Version        string               `json:"version,omitempty" mapstructure:"version,omitempty" yaml:"version,omitempty"`
    58→	Authentication AuthenticationConfig `json:"authentication,omitempty" mapstructure:"authentication" yaml:"authentication,omitempty"`
    59→	Authorization  AuthorizationConfig  `json:"authorization,omitempty" mapstructure:"authorization" yaml:"authorization,omitempty"`
    60→	Cors           CorsConfig           `json:"cors,omitempty" mapstructure:"cors" yaml:"cors,omitempty"`
