    66→	Analytics      AnalyticsConfig      `json:"analytics,omitempty" mapstructure:"analytics" yaml:"analytics,omitempty"`
    67→	Server         ServerConfig         `json:"server,omitempty" mapstructure:"server" yaml:"server,omitempty"`
    68→	Environments   EnvironmentsConfig   `json:"environments,omitempty" mapstructure:"environments" yaml:"environments,omitempty"`
    69→	Storage        StoragesConfig       `json:"storage,omitempty" mapstructure:"storage" yaml:"storage,omitempty"`
