    94→func Load(ctx context.Context, path string) (*Result, error) {
    95→	v := viper.New()
    96→	v.SetEnvPrefix(EnvPrefix)
    97→	v.SetEnvKeyReplacer(strings.NewReplacer(".", "_"))
    98→	v.AutomaticEnv()
    99→
   100→	var cfg *Config
   101→
   102→	if path == "" {
   103→		cfg = Default()
   104→	} else {
   105→		cfg = &Config{}
   106→		file, err := getConfigFile(ctx, path)
   107→		if err != nil {
   108→			return nil, err
   109→		}
   110→		defer file.Close()
   111→		stat, err := file.Stat()
   112→		if err != nil {
   113→			return nil, err
   114→		}
   115→
   116→		// reimplement logic from v.ReadInConfig()
   117→		v.SetConfigFile(stat.Name())
   118→		ext := filepath.Ext(stat.Name())
   119→		if len(ext) > 1 {
   120→			ext = ext[1:]
   121→		}
   122→		if !slices.Contains(viper.SupportedExts, ext) {
   123→			return nil, viper.UnsupportedConfigError(ext)
   124→		}
   125→		if err := v.ReadConfig(file); err != nil {
   126→			return nil, err
   127→		}
   128→
   129→		// This is a fix for issue #4428. By default, Viper uses lowercase keys and the allowed_teams with case-sensitive keys
   130→		// will be converted to lowercase. This will cause issues when matching against allowed_organizations. This workaround
   131→		// tries to restore the original case of the keys in allowed_teams if they match any of the allowed_organizations.
   132→		if v.IsSet("authentication.methods.github.allowed_teams") && v.IsSet("authentication.methods.github.allowed_organizations") {
   133→			allowedTeams := v.GetStringMapStringSlice("authentication.methods.github.allowed_teams")
   134→			orgs := (v.GetStringSlice("authentication.methods.github.allowed_organizations"))
   135→			for org, teams := range allowedTeams {
   136→				if slices.Contains(orgs, org) {
   137→					continue
   138→				}
   139→
   140→				if i := slices.IndexFunc(orgs, func(o string) bool {
   141→					return org == strings.ToLower(o)
   142→				}); i != -1 {
   143→					delete(allowedTeams, org)
   144→					allowedTeams[orgs[i]] = teams
   145→				}
   146→
   147→			}
   148→			v.Set("authentication.methods.github.allowed_teams", allowedTeams)
   149→		}
   150→	}
   151→
   152→	var (
   153→		result      = &Result{Config: cfg}
   154→		deprecators []deprecator
   155→		defaulters  []defaulter
   156→		validators  []validator
   157→	)
   158→
   159→	f := func(field any) {
   160→		// for-each deprecator implementing field we collect
   161→		// them up and return them to be run before unmarshalling and before setting defaults.
   162→		if deprecator, ok := field.(deprecator); ok {
   163→			deprecators = append(deprecators, deprecator)
   164→		}
   165→
   166→		// for-each defaulter implementing fields we invoke
   167→		// setting any defaults during this prepare stage
   168→		// on the supplied viper.
   169→		if defaulter, ok := field.(defaulter); ok {
   170→			defaulters = append(defaulters, defaulter)
   171→		}
   172→
   173→		// for-each validator implementing field we collect
   174→		// them up and return them to be validated after
   175→		// unmarshalling.
   176→		if validator, ok := field.(validator); ok {
   177→			validators = append(validators, validator)
   178→		}
   179→	}
   180→
   181→	// invoke the field visitor on the root config firsts
   182→	root := reflect.ValueOf(cfg).Interface()
   183→	f(root)
   184→
   185→	// these are reflected config top-level types for fields where
   186→	// they have been marked as experimental and their associated
   187→	// flag has enabled set to false.
   188→	var skippedTypes []reflect.Type
   189→
   190→	val := reflect.ValueOf(cfg).Elem()
   191→	for i := range val.NumField() {
   192→		// search for all expected env vars since Viper cannot
   193→		// infer when doing Unmarshal + AutomaticEnv.
   194→		// see: https://github.com/spf13/viper/issues/761
   195→		structField := val.Type().Field(i)
   196→		if exp := structField.Tag.Get("experiment"); exp != "" {
   197→			if !v.GetBool(fmt.Sprintf("experimental.%s.enabled", exp)) {
   198→				skippedTypes = append(skippedTypes, structField.Type)
   199→			}
   200→		}
   201→
   202→		key := fieldKey(structField)
   203→		bindEnvVars(v, getFliptEnvs(), []string{key}, structField.Type)
   204→
   205→		field := val.Field(i).Addr().Interface()
   206→		f(field)
   207→	}
   208→
   209→	// run any deprecations checks
   210→	for _, deprecator := range deprecators {
   211→		warnings := deprecator.deprecations(v)
   212→		for _, warning := range warnings {
   213→			result.Warnings = append(result.Warnings, warning.Message())
   214→		}
   215→	}
   216→
   217→	// run any defaulters
   218→	for _, defaulter := range defaulters {
   219→		if err := defaulter.setDefaults(v); err != nil {
   220→			return nil, err
   221→		}
   222→	}
   223→
   224→	if err := v.Unmarshal(cfg, viper.DecodeHook(
   225→		mapstructure.ComposeDecodeHookFunc(
   226→			append(DecodeHooks, experimentalFieldSkipHookFunc(skippedTypes...))...,
   227→		),
   228→	)); err != nil {
   229→		return nil, err
   230→	}
   231→
   232→	// run any validation steps
   233→	for _, validator := range validators {
   234→		if err := validator.validate(); err != nil {
   235→			return nil, err
   236→		}
   237→	}
   238→
   239→	return result, nil
   240→}
