   281→// fieldKey returns the name to be used when deriving a fields env var key.
   282→// If marked as squash the key will be the empty string.
   283→// Otherwise, it is derived from the lowercase name of the field.
   284→func fieldKey(field reflect.StructField) string {
   285→	if tag := field.Tag.Get("mapstructure"); tag != "" {
   286→		tag, attr, ok := strings.Cut(tag, ",")
   287→		if !ok || attr == "squash" || attr == "omitempty" {
   288→			return tag
   289→		}
   290→	}
   291→
   292→	return strings.ToLower(field.Name)
   293→}
