   337→const wildcard = "*"
   338→
   339→func appendIfNotEmpty(s []string, v ...string) []string {
   340→	for _, vs := range v {
   341→		if vs != "" {
   342→			s = append(s, vs)
   343→		}
   344→	}
   345→
   346→	return s
   347→}
