   455→func (c *Config) ServeHTTP(w http.ResponseWriter, r *http.Request) {
   456→	var (
   457→		out []byte
   458→		err error
   459→	)
   460→
   461→	if r.Header.Get("Accept") == "application/json+pretty" {
   462→		out, err = json.MarshalIndent(c, "", "  ")
   463→	} else {
   464→		out, err = json.Marshal(c)
   465→	}
   466→
   467→	if err != nil {
   468→		w.WriteHeader(http.StatusInternalServerError)
   469→		return
   470→	}
   471→
   472→	if _, err = w.Write(out); err != nil {
   473→		w.WriteHeader(http.StatusInternalServerError)
   474→		return
   475→	}
   476→}
