   478→// stringToEnumHookFunc returns a DecodeHookFunc that converts strings to a target enum
   479→func stringToEnumHookFunc[T constraints.Integer](mappings map[string]T) mapstructure.DecodeHookFunc {
   480→	return func(
   481→		f reflect.Type,
   482→		t reflect.Type,
   483→		data any,
   484→	) (any, error) {
   485→		if f.Kind() != reflect.String {
   486→			return data, nil
   487→		}
   488→		if t != reflect.TypeOf(T(0)) {
   489→			return data, nil
   490→		}
   491→
   492→		enum := mappings[data.(string)]
   493→
   494→		return enum, nil
   495→	}
   496→}
