   498→func experimentalFieldSkipHookFunc(types ...reflect.Type) mapstructure.DecodeHookFunc {
   499→	return func(
   500→		f reflect.Type,
   501→		t reflect.Type,
   502→		data any,
   503→	) (any, error) {
   504→		if len(types) == 0 {
   505→			return data, nil
   506→		}
   507→
   508→		if t.Kind() != reflect.Struct {
   509→			return data, nil
   510→		}
   511→
   512→		// skip any types that match a type in the provided set
   513→		for _, typ := range types {
   514→			if t == typ {
   515→				return reflect.New(typ).Interface(), nil
   516→			}
   517→		}
   518→
   519→		return data, nil
   520→	}
   521→}
