   523→// stringToReferenceHookFunc returns a DecodeHookFunc that handles:
   524→// - ${env:VAR} - environment variables
   525→// - ${secret:key} - secret references (marked as unresolved placeholders)
   526→func stringToReferenceHookFunc() mapstructure.DecodeHookFunc {
   527→	return func(
   528→		f reflect.Type,
   529→		t reflect.Type,
   530→		data any,
   531→	) (any, error) {
   532→		if f.Kind() != reflect.String || f != reflect.TypeFor[string]() {
   533→			return data, nil
   534→		}
   535→
   536→		str := data.(string)
   537→
   538→		// Handle explicit environment references: ${env:VAR}
   539→		if envReference.MatchString(str) {
   540→			key := envReference.ReplaceAllString(str, `$1`)
   541→			return os.Getenv(key), nil
   542→		}
   543→
   544→		// Secret references are left as-is and will be resolved post-load
   545→		return data, nil
   546→	}
   547→}
