   549→// stringToSliceHookFunc returns a DecodeHookFunc that converts
   550→// string to []string by splitting using strings.Fields().
   551→func stringToSliceHookFunc() mapstructure.DecodeHookFunc {
   552→	return func(
   553→		f reflect.Kind,
   554→		t reflect.Kind,
   555→		data any,
   556→	) (any, error) {
   557→		if f != reflect.String || t != reflect.Slice {
   558→			return data, nil
   559→		}
   560→
   561→		raw := data.(string)
   562→		if raw == "" {
   563→			return []string{}, nil
   564→		}
   565→
   566→		return strings.Fields(raw), nil
   567→	}
   568→}
