itempty\" mapstructure:\"secrets\" yaml:\"secrets,omitempty\"`\n\tTemplates      TemplatesConfig      `json:\"templates,omitempty\" mapstructure:\"templates\" yaml:\"templates,omitempty\"`\n}\n\ntype Result struct {\n\tConfig   *Config\n\tWarnings []string\n}\n\n// Dir returns the default root directory for Flipt configuration\nfunc Dir() (string, error) {\n\tconfigDir, err := os.UserConfigDir()\n\tif err != nil {\n\t\treturn \"\", fmt.Errorf(\"getting user config dir: %w\", err)\n\t}\n\n\treturn filepath.Join(configDir, \"flipt\"), nil\n}\n\nfunc Load(ctx context.Context, path string) (*Result, error) {\n\tv := viper.New()\n\tv.SetEnvPrefix(EnvPrefix)\n\tv.SetEnvKeyReplacer(strings.NewReplacer(\".\", \"_\"))\n\tv.AutomaticEnv()\n\n\tvar cfg *Config\n\n\tif path == \"\" {\n\t\tcfg = Default()\n\t} else {\n\t\tcfg = &Config{}\n\t\tfile, err := getConfigFile(ctx, path)\n\t\tif err != nil {\n\t\t\treturn nil, err\n\t\t}\n\t\tdefer file.Close()\n\t\tstat, err := file.Stat()\n\t\tif err != nil {\n\t\t\treturn nil, err\n\t\t}\n\n\t\t// reimplement logic from v.ReadInConfig()\n\t\tv.SetConfigFile(stat.Name())\n\t\text := filepath.Ext(stat.Name())\n\t\tif len(ext) > 1 {\n\t\t\text = ext[1:]\n\t\t}\n\t\tif !slices.Contains(viper.SupportedExts, ext) {\n\t\t\treturn nil, viper.UnsupportedConfigError(ext)\n\t\t}\n\t\tif err := v.ReadConfig(file); err != nil {\n\t\t\treturn nil, err\n\t\t}\n\n\t\t// This is a fix for issue #4428. By default, Viper uses lowercase keys and the allowed_teams with case-sensitive keys\n\t\t// will be converted to lowercase. This will cause issues when matching against allowed_organizations. This workaround\n\t\t// tries to restore the original case of the keys in allowed_teams if they match any of the allowed_organizations.\n\t\tif v.IsSet(\"authentication.methods.github.allowed_teams\") && v.IsSet(\"authentication.methods.github.allowed_organizations\") {\n\t\t\tallowedTeams := v.GetStringMapStringSlice(\"authentication.methods.github.allowed_teams\