    70→	sourceDriver, err := iofs.New(migrations.FS, fliptsql.Clickhouse.Migrations())
    71→	if err != nil {
    72→		return nil, fmt.Errorf("constructing migration source driver (db driver %q): %w", driver.Migrations(), err)
    73→	}
    74→
    75→	mm, err := migrate.NewWithInstance("iofs", sourceDriver, fliptsql.Clickhouse.Migrations(), dr)
    76→	if err != nil {
    77→		return nil, err
    78→	}
    79→
    80→	return mm, nil
    81→}
